BEGIN;

DELETE FROM route_waypoints WHERE route_code = 'THS4';
DELETE FROM service_routes WHERE route_code = 'THS4';

VALUES ('THS4', 'THS4', 'THS4 service imported from route waypoint files.', TRUE)
ON CONFLICT (code) DO UPDATE
SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  is_active = TRUE;

VALUES ('THS4', 'THS4', 
'THS4 - KRPUS/KRPNC/JPNAO/JPAXT/JPKIJ/KRPUS'
, 'ROUND', 'THS4 route imported from waypoint files.', TRUE);


COMMIT;
